const cooldown = env.get("delay") || 5000;
let lastSent = context.get("lastSent") || 0;
let queuedMsg = context.get("queuedMsg") || null;
let now = Date.now();

if (now - lastSent > cooldown) {
    // Send med det samme
    context.set("lastSent", now);
    return [msg, { "payload": "nodelay " + cooldown + " ms."}];
} else {
    // Gem besked til senere
    context.set("queuedMsg", msg);

    // Hvis der ikke allerede er en timer, start en
    if (!context.get("timerActive")) {
        context.set("timerActive", true);

        setTimeout(() => {
            let latest = context.get("queuedMsg");
            context.set("queuedMsg", null);
            context.set("lastSent", Date.now());
            context.set("timerActive", false);
            node.send([latest, { "payload": "passed " + cooldown + " ms."}]);
        }, cooldown);
    }

    return [null, { "payload": "delayed " + cooldown + " ms." }]; // Hold beskeden tilbage
}

const cooldown = env.get("delay") || 5000; // delay i ms, kan sættes via env-var
const topic = msg.topic || "_default"; // fallback hvis topic mangler

let state = context.get("state") || {};
let now = Date.now();

if (!state[topic]) {
    state[topic] = {
        lastSent: 0,
        queuedMsg: null,
        timerActive: false
    };
}

let topicState = state[topic];

if (now - topicState.lastSent > cooldown) {
    // Send med det samme
    topicState.lastSent = now;
    context.set("state", state);
    return [msg, { "payload": "nodelay " + cooldown + " ms." }];
} else {
    // Gem seneste besked
    topicState.queuedMsg = msg;

    if (!topicState.timerActive) {
        topicState.timerActive = true;

        setTimeout(() => {
            let latest = topicState.queuedMsg;
            topicState.queuedMsg = null;
            topicState.lastSent = Date.now();
            topicState.timerActive = false;
            context.set("state", state);
            node.send([latest, { "payload": "passed " + cooldown + " ms." }]);
        }, cooldown);
    }

    context.set("state", state);
    return [null, { "payload": "delayed " + cooldown + " ms." }];
}

