// Hjælpefunktion til at sikre, at en streng slutter med semikolon
function ensureSemicolon(queryString) {
    let trimmed = queryString.trim();
    if (trimmed.length === 0) return "";
    // Hvis den ikke slutter med ;, så tilføj det
    return trimmed.endsWith(";") ? trimmed : trimmed + ";";
}

// 2. Håndter msg.query (String, Array eller ingenting)
if (typeof msg.query === "string") {
    dynamicQueries.push(ensureSemicolon(msg.query));
} else if (Array.isArray(msg.query)) {
    // Kør igennem alle elementer i arrayet og giv dem et semikolon hvis de mangler
    msg.query.forEach(q => {
        if (typeof q === "string" && q.trim().length > 0) {
            dynamicQueries.push(ensureSemicolon(q));
        }
    });
}

// 3. Saml det hele med linjeskift
msg.payload = `${baseQuery}\n${dynamicQueries.join("\n")}`;

return msg;

